  onCheckboxChange(event: any, loan_key: any, index: any) {
    const selectedLoan =
      this.DisbOrdersResponseModal[
        index + this.pagingObject.pageSize * (this.pagingObject.page - 1)
      ];
    selectedLoan.isCheck = event.target.checked;
    this.updateSelectedLoan(loan_key, event.target.checked);
    this.updateMasterSingleLoanCheckbox();
    if (
      this.DisbOrdersResponseModal.length !== this.selectedSingleLoans.length
    ) {
      this.ionCheckBoxSingleLoan.indeterminate = true;
    } else if (
      this.DisbOrdersResponseModal.length == this.selectedSingleLoans.length
    ) {
      // console.log("not equal");
      this.ionCheckBoxSingleLoan.indeterminate = false;
      this.ionCheckBoxSingleLoan.checked = true;
    }
    if (this.selectedSingleLoans.length == 0) {
      // console.log("last if");
      this.ionCheckBoxSingleLoan.indeterminate = false;
    }
  }

  onCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.DisbOrdersResponseModal.forEach((loan) => (loan.isCheck = isChecked));
    this.updateSelectedLoanForAll(isChecked);
  }

  onCheckboxMasterChangeGroup(event: any) {
    const isChecked = event.target.checked;
    this.DisbOrdersResponseModal.forEach((loan) => (loan.isCheck = isChecked));
    this.updateSelectedLoanForAll(isChecked);
  }

  updateSelectedLoan(loan_key: any, isChecked: boolean) {
    console.log("updateSelectedLoan works");
    const index = this.selectedSingleLoans.indexOf(loan_key);
    if (isChecked && index === -1) {
      this.selectedSingleLoans.push(loan_key);
    } else if (!isChecked && index > -1) {
      this.selectedSingleLoans.splice(index, 1);
    }
  }

  updateSelectedLoanForAll(isChecked: boolean) {
    this.selectedSingleLoans = [];
    if (isChecked) {
      this.DisbOrdersResponseModal.forEach((loan) => {
        this.selectedSingleLoans.push(loan.loan_key);
      });
    }
  }

  updateMasterSingleLoanCheckbox() {
    const allSelected = this.DisbOrdersResponseModal.every(
      (loan) => loan.isCheck
    );
    const someSelected = this.DisbOrdersResponseModal.some(
      (loan) => loan.isCheck
    );

    if (allSelected) {
      this.isAllSingleLoansSelected = true;
    } else if (!someSelected) {
      console.log("some selected");
      this.ionCheckBoxSingleLoan.checked = false;
      this.ionCheckBoxSingleLoan.indeterminate = false;
      this.isAllSingleLoansSelected = false;
    }
  }

  //////////////////////////////////////GRID CONTROL For GROUP
  onCheckboxMasterChangeForGroups(event: any) {
    console.log("im working");
    const isChecked = event.target.checked;
    this.uniqueKeys.forEach((key) => {
      this.checkedKeys[key] = this.masterChecked;
      this.groupedData[key].forEach(
        (row) => (row.isCheck = this.masterChecked)
      );
    });
    this.updateSelectedLoanForGoups(isChecked);
  }

  onCheckboxChangeForGroup(event: any, key: string, index: any) {
    const selectedLoan =
      this.groupedData[key][
        index + this.pagingObject.pageSize * (this.pagingObject.page - 1)
      ];
    selectedLoan.isCheck = event.target.checked;
    const isChecked = this.checkedKeys[key];
    this.groupedData[key].forEach((row) => (row.isCheck = isChecked));
    this.updateSelectedLoanGroup(key, isChecked);
    this.updateMasterGroupLoanCheckbox();

    if (this.uniqueKeys.length !== this.selectedGroupLoans.length) {
      this.ionCheckBoxGroupLoan.indeterminate = true;
    } else if (this.uniqueKeys.length == this.selectedGroupLoans.length) {
      this.ionCheckBoxGroupLoan.indeterminate = false;
      this.ionCheckBoxGroupLoan.checked = true;
    }
    if (this.selectedGroupLoans.length == 0) {
      this.ionCheckBoxGroupLoan.indeterminate = false;
    }
  }

  updateSelectedLoanForGoups(isChecked: boolean) {
    this.selectedGroupLoans = [];
    if (isChecked) {
      this.selectedGroupLoans = this.masterChecked ? [...this.uniqueKeys] : [];
    }
  }

  updateSelectedLoanGroup(loan_key: any, isChecked: boolean) {
    console.log("updateSelectedLoan works");
    const index = this.selectedGroupLoans.indexOf(loan_key);
    if (isChecked && index === -1) {
      this.selectedGroupLoans.push(loan_key);
    } else if (!isChecked && index > -1) {
      this.selectedGroupLoans.splice(index, 1);
    }
  }

  updateMasterGroupLoanCheckbox() {
    // Determine if all rows are selected across all groups
    const allSelected = Object.values(this.groupedData).every((group) =>
      group.every((loan) => loan.isCheck)
    );

    // Determine if at least one row is selected across all groups
    const someSelected = Object.values(this.groupedData).some((group) =>
      group.some((loan) => loan.isCheck)
    );

    if (allSelected) {
      this.isAllGroupsLoansSelected = true;
    } else if (!someSelected) {
      console.log("some selected");
      this.ionCheckBoxGroupLoan.checked = false;
      this.ionCheckBoxGroupLoan.indeterminate = false;
      this.isAllGroupsLoansSelected = false;
    }
  }

  groupsPaging<T>(listInput: T[], page: number): T[] {
    const startIndex = (page - 1) * this.pageSize;
    const endIndex = startIndex + this.pageSize;
    return listInput?.slice(startIndex, endIndex);
  }

  updatePagedData() {
    const keysForCurrentPage = this.groupsPaging(
      this.uniqueKeys,
      this.currentPage
    );

    // Clear paged data and populate it with data for the current page
    this.pagedData = {};

    keysForCurrentPage.forEach((key) => {
      this.pagedData[key] = this.groupedData[key];
    });
  }

  changePaginationPageGroupLoans(newPage: number): void {
    this.currentPage = newPage;
    this.updatePagedData();
  }

  get totalPages(): number {
    return Math.ceil(this.totalCount / this.pageSize);
  }

  goToFirstPage(): void {
    this.changePaginationPageGroupLoans(1);
  }

  // Navigate to the last page
  goToLastPage(): void {
    this.changePaginationPageGroupLoans(this.totalPages);
  }

