  makeDisbOrders() {
    this.showLoader = true;
    if (this.disbursementForm.valid) {
      if (this.selectedOption == "custom-checked") {
        console.log("im hereeeeee");
        this.getDisbOrdersCSV();
      } else {
        this.http
          .post(
            this.env.API_URL +
              `api/Loan/MakeDisbOrders?org_code=${this.org_code_user_info}&disb_co_id=${this.disbursementLayoutForm.controls.disb_co_id.value}&loan_key_string=${this.selectedLoanString}`,
            {}
          )

          .subscribe({
            next: (data) => {
              this.alertService.InfoAlert("تم تنفيذ امر الصرف بنجاح", true);
              this.getDisbOrdersCSV();
            },
            error: (err) => {
              console.log(err);
              this.alertService.showAlertError(err.error, false);
            },
          });
      }
    }
  }

